var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아...... 동전도 다 떨어졌네......","JPN":"あ……コインがもう無くなる……","ENG":"Ugh... I've run out of coins...","TWN":"啊……硬幣也都用完了……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님, 뭐 더 던질 거 없어요?","JPN":"警視様、何か他に投げるものありません？","ENG":"Major, do you have anything I could throw?","TWN":"警正，沒有什麼可以丟的東西了嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......없어.","JPN":"……ないわよ。","ENG":"No.","TWN":"……沒了。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그런 말은 찾아보는 시늉이라도 하고 하셔야 설득력이 있지 않을까요?","JPN":"もう少し探してくれたっていいんじゃないですか？","ENG":"Could you at least pretend to check what's in your pockets before you answer me?","TWN":"妳起碼假裝找找看再下結論啊，這樣說不是很沒說服力嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"일단 그 양말이라도 좀 벗어서 주시면......","JPN":"とりあえず、その靴下だけでも脱いでくれると……","ENG":"Then can you give me your socks, so I could...","TWN":"妳稍微脫個襪子……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"없다고!!","JPN":"ないってば！！","ENG":"No!","TWN":"我都說沒有了！！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"도대체 지금 사태를 이해는 하고 있는 거야? 강소영 경위!","JPN":"今のこの状況、本当にわかってるの？　マエカワ警部補！","ENG":"Do you understand the situation we're in, Lieutenant Kang?","TWN":"妳到底有沒有理解，現在是什麼情況啊？姜素英警衛！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"우린 지금 극악 범죄자 놈들에게 붙잡힌 상황이라고!","JPN":"私たちは今、極悪非道な犯罪者集団に捕まってるの！","ENG":"We're currently held captive by an atrocious band of criminals!","TWN":"我們現在被窮凶惡極的犯罪者抓住了！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"민간인도 아니고 경찰이!","JPN":"民間人でもなく、警察が！","ENG":"Us! The police!","TWN":"不是平民，而是我們這些警察！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"범죄자 놈들에게!!","JPN":"犯罪者どもに捕まって！！","ENG":"Taken prisoner!","TWN":"被犯罪者們！！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"포로 신세라니!!!","JPN":"捕虜になってるなんて！！","ENG":"By the criminals!","TWN":"俘虜了啊！！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이건 경찰 공무원으로서 도저히 용납 못할 수치야, 수치!!","JPN":"これは、警察として到底容認できない恥よ！！","ENG":"We're an utter embarrassment to the members of the law enforcement community!","TWN":"這是作為公務員的警察無法被容忍的羞恥啊，羞恥！！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아, 네...... 참 부끄럽네요......","JPN":"あ、はい……恥ずかしい限りですよね……","ENG":"Yeah, yeah. My face is red with shame.","TWN":"啊，是啊……真是丟臉呢……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그러니까 무모하게 싸우지 말고 프리라이더 분들처럼 도망치자고 했더니......","JPN":"だから、無謀に突っ込まずに、フリーライダーズのように逃げようって提案したのに……","ENG":"Then why didn't you listen when I told you we should run, like Freedom Riders did?","TWN":"所以我才說不該魯莽地戰鬥，要像免費騎士那樣逃跑……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그, 그, 그거야 어쨌든!!","JPN":"そ、そ、それはともかく！！","ENG":"H-hey! That's unfair of you to bring that up!","TWN":"那、那、不管啦！！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"지금 장난이나 치고 있을 생각이 들어?!","JPN":"今はふざけてる場合じゃないでしょ！？","ENG":"Anyway, this isn't the time to fool around.","TWN":"妳現在還有心情玩嗎？！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"아까부터 잡동사니를 자꾸 밖으로 던지면서 뭘 하고 있는 거야?!","JPN":"さっきから、ひっきりなしにがらくたを外に投げて、どういうつもり！？","ENG":"Why on earth do you keep throwing stuff outside?","TWN":"妳從剛剛就一直往外面丟些亂七八糟的東西，這是在幹嘛啊？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"장난치고 있는 거 아닌데......","JPN":"ふざけてるわけじゃないのに……","ENG":"I'm not playing around.","TWN":"我沒有在鬧……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"나름대로 열심히 탈출 작전을 수행 중이거든요?","JPN":"私なりに脱出作戦を実行しているんですよ？","ENG":"This is part of my escape plan.","TWN":"我是很認真地在實施我的逃脫作戰呢！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"탈출 작전은 무슨!!","JPN":"脱出作戦なわけあるか！！","ENG":"Oh, give me a break!","TWN":"什麼逃脫作戰？！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"잡동사니 투척이랑 탈출이 무슨 상관인데?!!","JPN":"がらくたを投げるのと脱出に何の関係が！？","ENG":"How are you going to get us out by chucking things outside?","TWN":"亂丟雜物和逃脫作戰有什麼關係？！！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아...... 정신 사나워......","JPN":"あ……これは話が通じないな……","ENG":"Gosh, you're distracting...","TWN":"啊……沒辦法專心……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"저기요! 운전사 아저씨?","JPN":"あのー！　運転手さん！","ENG":"Excuse me, Mr. Driver!","TWN":"打擾一下！司機大叔？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"혹시 남는 자리 있으면 저만 다른 호송차로 좀 옮겨 주시면 안될까요?","JPN":"もし他の車両に空きがあれば、私だけ移してもらえませんか？","ENG":"Is there a chance you have space in other vehicles that I can travel in?","TWN":"要是還有多餘的位置的話，能不能用其他的押送車單獨押送我啊？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"시끄러워! 포로 주제에 별 걸 다 바라는군.","JPN":"やかましい！　捕虜のくせに聞いてもらえると思うか？","ENG":"Shut up! What makes you think a prisoner like you could make a request?","TWN":"吵死了！妳一個俘虜還有這麼多要求。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"남는 자리 따윈 없으니까 싫으면 내려서 걷든가!","JPN":"空きなんかないから、ここがイヤなら降りて歩け！","ENG":"There's no spare space for you. You shut your mouth, or get off and start walking!","TWN":"沒有多餘的位置啦，妳不爽就走過去啊！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 그건 다리 아플 것 같아서 좀 싫네요.","JPN":"はは、それは足が疲れそうでイヤですね。","ENG":"Hah hah, that's going to be a bit too exhausting, isn't it?","TWN":"哈哈，那樣腿會痛吧，有點討厭呢。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그보다 운전사 아저씨......","JPN":"それより、運転手さん……","ENG":"By the way, Mr. Driver.","TWN":"話說，司機大叔……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"혹시 자수하실 생각 없으세요?","JPN":"ひょっとして、自首するつもりはありませんか？","ENG":"Would you by any chance want to turn yourself in?","TWN":"你有沒有想過要自首？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"무, 뭐......?","JPN":"は、はあ……？","ENG":"W-what?","TWN":"什、什麼……？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"가, 강소영 경위? 드디어 머리가 어떻게 되기라도 했어?","JPN":"マ、マエカワ警部補？　とうとう頭がおかしくなっちゃったの？","ENG":"L-Lieutenant! Have you gone mad or something?","TWN":"姜、姜素英警衛？妳腦袋進水了嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"지금 무슨 소릴 하는 거야?","JPN":"いったい何言ってるの？","ENG":"What are you talking about?","TWN":"妳在說什麼啊？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그러지 마시고 자수하세요. 제가 잘해드릴게요.","JPN":"本当に自首のこと、真剣に検討してくださいよ。私が話を通してあげますから。","ENG":"Come on, turn yourself in, will you? I promise, I'll be nice.","TWN":"別再這樣了，自首吧。我會善待你的。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"같은 자수라고 해도 담당 형사에 따라서 정상참작 수준이 다른 거 아시죠?","JPN":"同じ自首でも、担当刑事によって情状酌量が違ってくるのはご存知ですよね？","ENG":"You know, your sentence can vary greatly depending on the detective that's going to interrogate you.","TWN":"就算都是自首，但向負責的刑警自首，酌情處理的程度也是不一樣的，你知道吧？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"제가 그래도 우리 서에서는 이빨이 좀 먹히는 편이거든요.","JPN":"こう見えても私、警察署では結構顔が利くほうなんですよ。","ENG":"Thing is, I'm kind of high up in the agency, you know.","TWN":"我在我們局裡算是好說話的。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"지금 저한테 자수하시면 최대한 형량이 깎이도록 기소장에 잘 써드릴 수 있는......","JPN":"今ここで自首されたら、できるだけ減刑されるように起訴状に書いて……","ENG":"If you turn yourself in now, I promise I'll be very generous when I'm writing my report.","TWN":"你現在向我自首的話，我就在起訴狀裡給你寫最大限度的減刑……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"시끄럽다고 했지!!","JPN":"やかましいって言っただろうが！！","ENG":"That’s enough!","TWN":"妳吵死了！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"한마디만 더 하면 차 밖에 묶어서 끌고 갈 거야!","JPN":"もう一言喋ったら、車に縛り付けて引きずりまわすからな！","ENG":"One more word, and I will tie you down on the roof.","TWN":"妳再說一句，我就把妳綁在車外拖著走！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"미, 민서 양? 정말 하실 건가요?","JPN":"ヒ、ヒミコさん？　本当にやるつもりですか？","ENG":"M-Minseo! Are you sure you want to do this?","TWN":"旼、旼序小姐？真的要這樣做嗎？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"무, 물론 제가 무서워서 하는 이야기는 아니고요......","JPN":"も、もちろんビビってるわけではありませんが……","ENG":"I-I'm not scared or anything, but...","TWN":"我、我會這樣說當然不是因為我害怕……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그, 그래요? 역시 히로세 씨는 대단해요......","JPN":"ほ、本当ですか？　さすが廣瀬さんですね……","ENG":"R-really? You're amazing, Ms. Hirose...","TWN":"是、是嗎？廣瀨小姐果然很厲害呢。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"전 무서워서 당장이라도 주저앉을 것 같은데......","JPN":"ヒミコは怖くて、今にも座り込んじゃいそうですが……","ENG":"My legs are so shaky that I feel like I will collapse any minute...","TWN":"我害怕得隨時都會癱坐在地上……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"아니, 사실은 나도......","JPN":"いや、実は秋も……","ENG":"A-actually, it's not so different for me...","TWN":"不，其實我也是……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"이, 이게 아니라!! 하여튼 정말 저 녀석들과 싸울 수 있겠어요?","JPN":"じゃなくて！！　とにかく、本当にあいつらと戦うつもりですか？","ENG":"N-no, that's not it! Anyway, are you sure we could fight them?","TWN":"不、不是在說這個！我們真的能和那些傢伙們戰鬥嗎？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"우리 싸움 실력은...... 별로 기대할 게 없잖아요......","JPN":"秋たちの攻撃力は……期待できないじゃないですか……","ENG":"We aren't exactly good at fighting...","TWN":"我們的戰鬥實力……不是沒什麼好期待的嗎……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"하, 하지만......","JPN":"で、ですが……","ENG":"B-but...","TWN":"但、但是……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"이대로 두면 잡혀간 경찰 분들이 어떻게 될지 몰라요......","JPN":"このままだと、捕まってしまった警察組がどうなるか……","ENG":"God knows what they'll do to the police officers if we let them be...","TWN":"再這樣下去，被抓走的警察不知道會怎麼樣……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"어쩌면...... 지난번에 에이미처럼......","JPN":"もしかしたら……以前のエイミーのようになるかも……","ENG":"Remember what happened to Amy last time?","TWN":"說不定……會像上次艾米一樣……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그, 그건...... 그렇지만요......","JPN":"そ、それは……そうですけど……","ENG":"W-well, that’s true, but...","TWN":"那、那個……可是……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"아, 아무리 무서워도...... 그때처럼 후회하고 싶진 않아요......","JPN":"ど、どんなに怖くても、あの時のように後悔したくはありません。","ENG":"N-no matter how scared I am, I really don't want to be lost in regret like that other time...","TWN":"就、就算我再怎麼害怕……也不想像上次那樣後悔了……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"히, 히로세 씨도 그렇죠?","JPN":"ひ、廣瀬さんもそうですよね？","ENG":"Don't you feel the same, Ms. Hirose?","TWN":"廣、廣瀨小姐也是這麼想的吧？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"......민서 양 말이 맞아요.","JPN":"……ヒミコさんの言うとおりです。","ENG":"Actually, you're right.","TWN":"……旼序小姐說得對。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"저도...... 그런 일은 두 번 다시 겪고 싶지 않아요.","JPN":"秋も……あんなことは、二度と御免です。","ENG":"I don't ever want to go through something like that again.","TWN":"我也……不想再經歷那樣的事情了。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그, 그럼 이제부터 경찰 분들을 구하러 가죠!","JPN":"だ、だったら、これから警察組を助けに行きましょ！","ENG":"Th-then let's go save the police officers!","TWN":"那、那我們現在就去營救警察他們吧！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"잘 부탁드립니다!","JPN":"よろしくお願いします！","ENG":"I'll count on you!","TWN":"請多多指教！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"저, 저도요!!","JPN":"こ、こちらこそ！！","ENG":"I-I'll count on you, too!","TWN":"我、我也是！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그, 그런데...... 싸우다가 항복하면...... 받아주긴 하겠죠?","JPN":"と、ところで、途中で降参しても敵さんが受け入れてくれますよね？","ENG":"J-just one thing... Do you think they would spare our lives if we surrender in the middle of the fight?","TWN":"但、但是……在戰鬥中向對方投降的話……他們會接受吧？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"아, 아마도......?","JPN":"た、たぶん……？","ENG":"W-well, don't they have to?","TWN":"應、應該吧……？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"저기로군.","JPN":"あそこだ。","ENG":"There.","TWN":"就是那裡吧。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그 여형사 나리가 머리가 좋군.","JPN":"あの女刑事、頭が切れるな。","ENG":"She is one smart detective.","TWN":"那個女刑警還真是聰明呢。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"순찰대가 본대와 많이 떨어져 있어서 걱정했는데......","JPN":"パトロール隊が本隊とずいぶん離れていたから、心配したが……","ENG":"I was worried that the patrol unit was too far away from their base,","TWN":"我本來還擔心巡邏隊和主力部隊距離很遠……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"길잡이로 삼을 만한 소지품을 중간중간 떨어트려 둘 줄이야.","JPN":"道しるべになるよう、所持品を所々落としてくれるとはな。","ENG":"but she left her belongings here and there to mark her trail.","TWN":"沒想到她竟然沿途丟下了隨身物品，為我們指引道路。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"어때? 경찰 나리들 위치는 찾았나?","JPN":"どうだ？　警察組の位置は判明したか？","ENG":"How's it going? Have you located the police ladies?","TWN":"怎麼樣？找到警察大人們的位置了嗎？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"......저기, 가운데 트럭에 카운터용 구속구를 차고 있는 것 같아.","JPN":"……あの真ん中のトラックで、カウンター用の拘束装置をつけてるみたい。","ENG":"They're in that truck over there. It seems they're wearing anti-Counter restraints on them.","TWN":"……那台卡車上好像有制裁者拘束器的樣子。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L36_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"꼼지락거리는 걸 보니까 많이 다치지는 않은 것 같은데?","JPN":"見たところ、大したケガはしてないかも？","ENG":"They're moving. They don't seem to be hurt so badly.","TWN":"不過看他們動來動去的樣子，似乎沒有受傷？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"좋아, 그럼 잠입 방법이 문제인데......","JPN":"そうか、じゃあ、どうやって潜り込むかだが……","ENG":"Alright, the problem is how we start.","TWN":"很好，那現在問題就是要如何潛入了……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"잠깐, 존...... 저기 우리보다 먼저 온 손님이 있는 것 같은데?","JPN":"待って、ジョン。あそこに先客が来てるみたいだけど？","ENG":"Wait, John. It seems there are other people with the same goal here.","TWN":"等等，約翰……好像有人比我們先到了。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐? 어디......?","JPN":"なに？　どこだ……？","ENG":"Huh? Where?","TWN":"什麼？哪裡……？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"저, 정지하세요! 악의 무리 여러분!!","JPN":"と、止まりなさい！　悪党の皆さん！！","ENG":"S-stop right there, Mr. and Mrs. Villains!","TWN":"不，不要動！你們這些壞人！！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"우, 우리는 세상의 빛과 정의의 수호자! 프리덤 라이더입니다!","JPN":"わ、我々は世界の光と正義の守護者！　フリーダム・ライダーズです！","ENG":"W-we're the guardians of the light and justice, the Freedom Riders!","TWN":"我，我們是光明和正義的守護者！自由騎士！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그, 그래요! 그리고 다, 당장...... 붙잡고 계신 경찰 님들을 풀어주시기를 요, 요구합니다!","JPN":"そ、そうです！　た、ただちに……警察の皆さんの解放を、も、求めます！","ENG":"Y-yeah! W-we demand you that you release the police officers that you're holding captive!","TWN":"沒、沒錯！然後現在……我命、命令你們馬上把警察們給放了！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그, 그렇지 않으면......","JPN":"そ、そうしなければ……","ENG":"O-or else!","TWN":"否、否則……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그렇지 않으면!!","JPN":"そうしないなら！！","ENG":"Or else...","TWN":"否則！！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"어, 어쩌죠......?","JPN":"ど、どうします……？","ENG":"W-what should we say after \\"or else?\\"","TWN":"要、要怎麼辦……？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그, 글쎄요...... 역시 폭력적인 방법은 좀......","JPN":"さ、さあ……やっぱり暴力的なやり方はちょっと……","ENG":"I-I don't know... But we don't want to come off as too violent, do we?","TWN":"這、這個嘛……暴力的方法果然有點……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"뭐야, 저것들은?","JPN":"なんだ、あいつら？","ENG":"What are they?","TWN":"搞什麼啊，這些傢伙？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"조금 전에 놓친 침입자들인 것 같습니다!","JPN":"さっき逃した侵入者のようです！","ENG":"It seems they're the intruders that got away a while back!","TWN":"好像是之前逃走的侵入者！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"......알아서 나타나다니 수색대 일이 줄었군.","JPN":"……自ら現れるとは、捜索隊の仕事を減らしてくれたな。","ENG":"Huh, they chose to show up themselves. That's one less job for us.","TWN":"……他們自己出現倒是給搜索隊省了不少麻煩。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"뭘 멍청히 보고 있나? 당장 제압해! 어려우면 사살해도 좋다!","JPN":"何をぼうっとしてる？　今すぐ制圧しろ！　何なら、射殺しても良い！","ENG":"What are you gaping at? Subdue them, now! Shoot them dead, if necessary!","TWN":"還發什麼呆啊？立刻制服他們！難以制服的話直接擊斃也可以！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"꺄아악! 사, 살려줘요 히로세 씨!!","JPN":"きゃああ！　た、助けて、廣瀬さん！！","ENG":"Aaaah! H-help, Ms. Hirose!","TWN":"呀啊啊啊！救、救命啊，廣瀨小姐！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"다, 다리는 놓고 말해요!!","JPN":"あ、脚を離してから言ってよ！！","ENG":"L-let go of my leg!","TWN":"別、別抓著我的腿啊！！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"경찰 나리들을 구하러 온 모양이군!","JPN":"警察組を助けにきたようだな！","ENG":"They're here to rescue the cops.","TWN":"原來是來救警察大人他們的！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"프리라이더라고 했던가? 소심한 줄만 알았더니 꽤 강단이 있는데?","JPN":"フリーライダーだっけか？　ヤワだと思ったが、かなり勇敢なんだな。","ENG":"Free Riders, was it? I never thought they were bold enough to do something like this.","TWN":"他們說他們是自由騎士？我以為他們很膽小呢，沒想到挺有魄力嘛。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"하지만 강단만큼 실력이 받쳐주진 못하는 것 같아.","JPN":"でも、勇敢なだけで実力は備わってないみたい。","ENG":"But they don't have the skills to back up their boldness.","TWN":"但他們的實力好像撐不起他們的魄力呢。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"놈들에게 당하기 전에 빨리 도와주러 가라고.","JPN":"奴らにやられる前に、早く助けにいきなさいよ。","ENG":"You should go help them before they all go down.","TWN":"在他們受傷之前，你們快點去幫忙吧。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"도와주러 가라니? 그럼 넌?","JPN":"ひとりで行けって言うのか？　あんたは？","ENG":"Huh? What are you going to do?","TWN":"我們？那妳呢？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"그야 잠입은 내 특기잖아?","JPN":"アタシは潜入専門だから。","ENG":"My specialty is doing things quietly.","TWN":"因為潛入不是我的專長嗎？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"너희가 정면에서 시선을 끌어주면 내가 경찰 나리들을 구출한다.","JPN":"あなたたちが正面から注意を引いてくれたら、その隙にアタシが警察組を救出する。","ENG":"I'm going to get the police ladies out while you keep them busy at the front.","TWN":"在你們從正面吸引他們視線的時候，我就去把警察大人們救出來。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"어때? 좋은 작전이지?","JPN":"どう？　良い作戦でしょ？","ENG":"It's a perfect plan, isn't it?","TWN":"怎麼樣？很棒的作戰吧？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......말을 꺼낸 사람의 신용도만 제외하면 훌륭한 작전이군.","JPN":"……提案した人間の信用さえ除けば、素晴らしい作戦だな。","ENG":"It is, except that the one that's suggesting it isn't a very credible ally.","TWN":"……除了提出這個作戰的人的信用之外，的確是很不錯。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"우리에게만 위험한 일을 맡기려는 속셈은 아니겠지?","JPN":"俺らに危険な仕事を押し付けるつもりじゃないよな？","ENG":"You're not trying to leave all the hard work to us, are you?","TWN":"妳沒有心懷鬼胎，想把危險的事情都交給我們吧？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"자꾸 섭섭한 말씀을 하시네......","JPN":"そんなさびしいこと言わないでよ……","ENG":"Now you're making me sad.","TWN":"你總是會說些傷人的話呢……"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"뭣하면 같이 가줄까?","JPN":"何なら一緒に行きましょうか？","ENG":"I'll happily go with you, if you want.","TWN":"不然我們一起去吧？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"물론 싸움은 내 방식대로 하겠지만.","JPN":"もちろん、アタシのやり方で戦うけど。","ENG":"Of course, the combat will turn out the way I like it.","TWN":"當然，我會用我自己的方式戰鬥。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......생각해 보니 그것도 별로 내키진 않는군.","JPN":"……それはそれで気が進まないな。","ENG":"Come to think of it, that won't look so favorable either.","TWN":"……這麼一想，這樣我也不太樂意。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그럼 경찰 나리들을 부탁하지.","JPN":"では、警察組のほうを頼む。","ENG":"Then I'll leave the police ladies to you.","TWN":"那麼警察大人就交給妳了。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......그쪽도 준비됐나?","JPN":"……そっちも準備は済んだか？","ENG":"You ready?","TWN":"……你們那邊也準備好了嗎？"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"......물론.","JPN":"……もちろん。","ENG":"Yeah.","TWN":"……當然。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"우리도 준비 완료야!","JPN":"俺らも準備完了だ！","ENG":"We're ready as well.","TWN":"我們也準備完畢！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"좋아! 프리덤 라이더와 함께 리플레이서 부대를 격파한다!","JPN":"よし！　フリーダム・ライダーズとともに、リプレイサー部隊を撃破だ！","ENG":"Good. We're going to take down the Replacer troops with the Freedom Riders!","TWN":"很好！和自由騎士一起擊敗克隆部隊吧！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다들 가자고!","JPN":"みんな、行くぞ！","ENG":"Let's move!","TWN":"大家上啊！"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};